+/// Deterministic grid/cell geometry derived from CSS metrics + DPR + zoom.
+#[derive(Debug, Clone, Copy, PartialEq)]
+pub struct GridGeometry {
+    pub cols: u16,
+    pub rows: u16,
+    pub pixel_width: u32,
